import base64
import zlib
from datetime import datetime, timedelta
import uuid
from urllib.parse import urlencode
import requests


class SAMLServiceProvider:
    def __init__(self, issuer, acs_url):
        self.issuer = issuer
        self.acs_url = acs_url
    
    def generate_request_id(self):
        return "_" + str(uuid.uuid4())
    
    def get_timestamp(self):
        return datetime.utcnow().isoformat() + "Z"
    
    def get_not_on_or_after(self):
        return (datetime.utcnow() + timedelta(minutes=5)).isoformat() + "Z"
    
    def build_authn_request(self, destination_url, user_email=None, user_name=None, custom_attributes=None):
        request_id = self.generate_request_id()
        issue_instant = self.get_timestamp()
        
        saml_request = f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                     xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                     ID="{request_id}"
                     Version="2.0"
                     IssueInstant="{issue_instant}"
                     Destination="{destination_url}"
                     AssertionConsumerServiceURL="{self.acs_url}"
                     ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{self.issuer}</saml:Issuer>"""
        
        if user_email or user_name or custom_attributes:
            saml_request += "\n    <saml:Subject>"
            if user_email:
                saml_request += f"""
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{user_email}</saml:NameID>"""
            elif user_name:
                saml_request += f"""
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified">{user_name}</saml:NameID>"""
            saml_request += """
    </saml:Subject>"""
        
        if custom_attributes:
            saml_request += "\n    <saml:AttributeStatement>"
            for attr_name, attr_value in custom_attributes.items():
                saml_request += f"""
        <saml:Attribute Name="{attr_name}">
            <saml:AttributeValue>{attr_value}</saml:AttributeValue>
        </saml:Attribute>"""
            saml_request += """
    </saml:AttributeStatement>"""
        
        saml_request += """
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
                        AllowCreate="true"/>
    <samlp:RequestedAuthnContext Comparison="exact">
        <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
    </samlp:RequestedAuthnContext>
</samlp:AuthnRequest>"""
        
        return saml_request
    
    def encode_saml_request(self, saml_request, use_deflate=True):
        if use_deflate:
            compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
            encoded = base64.b64encode(compressed).decode('utf-8')
        else:
            encoded = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
        return encoded
    
    def send_authn_request(self, destination_url, user_email=None, user_name=None, 
                          custom_attributes=None, relay_state=None, use_deflate=True,
                          method='POST'):
        saml_request = self.build_authn_request(
            destination_url, 
            user_email=user_email,
            user_name=user_name,
            custom_attributes=custom_attributes
        )
        
        encoded_request = self.encode_saml_request(saml_request, use_deflate=use_deflate)
        
        if method.upper() == 'POST':
            return self._send_post_request(destination_url, encoded_request, relay_state)
        else:
            return self._send_redirect_request(destination_url, encoded_request, relay_state)
    
    def _send_post_request(self, destination_url, encoded_request, relay_state=None):
        data = {
            'SAMLRequest': encoded_request
        }
        if relay_state:
            data['RelayState'] = relay_state
        
        response = requests.post(destination_url, data=data)
        return response
    
    def _send_redirect_request(self, destination_url, encoded_request, relay_state=None):
        params = {
            'SAMLRequest': encoded_request
        }
        if relay_state:
            params['RelayState'] = relay_state
        
        redirect_url = destination_url + '?' + urlencode(params)
        response = requests.get(redirect_url, allow_redirects=True)
        return response
    
    def build_html_post_form(self, destination_url, user_email=None, user_name=None,
                            custom_attributes=None, relay_state=None):
        saml_request = self.build_authn_request(
            destination_url,
            user_email=user_email,
            user_name=user_name,
            custom_attributes=custom_attributes
        )
        
        encoded_request = self.encode_saml_request(saml_request, use_deflate=False)
        
        relay_input = f'<input type="hidden" name="RelayState" value="{relay_state}"/>' if relay_state else ''
        
        html_form = f"""<!DOCTYPE html>
<html>
<head>
    <title>SAML Authentication</title>
</head>
<body onload="document.forms[0].submit()">
    <form method="POST" action="{destination_url}">
        <input type="hidden" name="SAMLRequest" value="{encoded_request}"/>
        {relay_input}
        <noscript>
            <input type="submit" value="Continue"/>
        </noscript>
    </form>
</body>
</html>"""
        
        return html_form


